class Solution:
    def wordBreak(self, s, wordDict):
        words = set(wordDict)
        n = len(s)
        results = []
        def backtrack(i, parts):
            if i == n:
                results.append(' '.join(parts))
                return
            for j in range(i + 1, n + 1):
                w = s[i:j]
                if w in words:
                    parts.append(w)
                    backtrack(j, parts)
                    parts.pop()
        backtrack(0, [])
        return results

