class Solution:
    def wordBreak(self, s, wordDict):
        words = set(wordDict)
        n = len(s)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def solve(i):
            if i == n:
                return ['']
            out = []
            for j in range(i + 1, n + 1):
                w = s[i:j]
                if w in words:
                    for rest in solve(j):
                        out.append(w if rest == '' else w + ' ' + rest)
            return out
        return list(solve(0))

