var wordBreak = function(s, wordDict) {
    const words = new Set(wordDict);
    const n = s.length;
    const memo = new Map();
    function solve(i) {
        if (i === n) return [''];
        if (memo.has(i)) return memo.get(i);
        const out = [];
        for (let j = i + 1; j <= n; j++) {
            const w = s.slice(i, j);
            if (words.has(w)) {
                for (const rest of solve(j)) {
                    out.push(rest === '' ? w : w + ' ' + rest);
                }
            }
        }
        memo.set(i, out);
        return out;
    }
    return solve(0).slice();
};
